        private void MonthWiseFuelReport_Load(object sender, EventArgs e)
        {
            bunkfind();
            comboitem();
            frmdate.Value = DateTime.Today.AddDays(-1);
            todate.Value = DateTime.Today.AddDays(0);

            combocompcode_SelectedIndexChanged(sender,e);
        }
        void bunkfind()
        {

            DataTable dt = mas.bunkfind(Class.Users.HCompcode);
            if (dt.Rows.Count == 1)
            {
                combobunk.DisplayMember = "BUNKNAME";
                combobunk.ValueMember = "ASPTBLPETMASID";
                combobunk.DataSource = dt; combobunk.Enabled = false;
            }
            else
            {
                combobunk.DisplayMember = "BUNKNAME";
                combobunk.ValueMember = "ASPTBLPETMASID";
                combobunk.DataSource = dt; combobunk.Enabled = true;
            }
        }
