STid=A.VEHICLETYPE      JOIN GTGENITEMMAST H ON H.GTGENITEMMASTID=B.ITEMNAME      JOIN ASPTBLPETMAS I ON I.COMPCODE=D.GTCOMPMASTID AND I.COMPCODE=A.COMPCODE  AND  I.ASPTBLPETMASID=A.BUNKNAME     join GTDEPTDESGMAST j on   J.GTDEPTDESGMASTID=F.DEPTNAME     WHERE D.COMPCODE = '" + Class.Users.HCompcode + "' AND A.TOKENDATE between TO_DATE('" + frmdate.Value.ToString("dd-MM-yyyy") + "','dd-MM-yyyy') and TO_DATE('" + todate.Value.ToString("dd-MM-yyyy") + "','dd-MM-yyyy') AND I.BUNKNAME='" + combobunk.Text + "')X    GROUP BY X.COMPCODE,X.VEHICLENO, X.VEHTYPE ,X.FNAME,X.ITEMNAME,X.DEPT ,X.BUNKNAME,X.ACTIVE ,X.TOKENDATE,X.REMARKS,X.TODATE ORDER BY 9";

