                            }
                            else
                            {
                                string sel2 = "SELECT  X.COMPCODE, X.VEHICLENO, X.VEHTYPE ,X.FNAME as EMPNAME,  X.ITEMNAME,X.DEPT,X.BUNKNAME,X.ACTIVE,SUM(X.FUELRATE2) AS FUELRATE2, SUM(X.LITRES)LITRES ,SUM(X.FUELRATE2*X.LITRES) TOTAL,X.REMARKS AS FUELDATEA,X.TODATE  FROM  (   SELECT D.COMPCODE, (  SELECT  AA.VEHICLENO    FROM HRVEHMAST AA  JOIN HRVEHTYPEMAST Ab on AA.VEHICLETYPE=AB.HRVEHTYPEMASTID     JOIN GTCOMPMAST AC ON AC.GTCOMPMASTID=AA.COMPCODE  AND AA.ACTIVE='T'    WHERE  AA.HRVEHMASTID=A.VEHICLENO UNION ALL    SELECT BA.VEHICLENO  FROM ASPTBLVEHMAS BA  JOIN HRVEHTYPEMAST BB ON BA.VEHICLETYPE=BB.HRVEHTYPEMASTID   JOIN GTCOMPMAST BC ON BC.GTCOMPMASTID=BA.COMPCODE AND BA.ACTIVE='T'      WHERE  BA.ASPTBLVEHMASID=A.VEHICLENO) AS VEHICLENO, G.VEHTYPE , CONCAT(E.fname, concat('-', F.MIDCARD))  AS FNAME,  H.ITEMNAME,F.DEPT,  ( SELECT max(AA.FUELRATE2) AS FUELRATE2 FROM ASPTBLFUELRATEMASDET AA JOIN GTCOMPMAST AB  ON AA.COMPCODE = AB.GTCOMPMASTID   JOIN GTGENITEMMAST AC ON AC.GTGENITEMMASTID = AA.ITEMNAME WHERE AB.COMPCODE = D.COMPCODE AND AC.GTGENITEMMASTID = AA.ITEMNAME AND AC.ITEMNAME = H.ITEMNAME   AND AA.FUELDATE = (SELECT MAX(ZAA.FUELDATE) FROM ASPTBLFUELRATEMASDET ZAA JOIN GTCOMPMAST ZAB  ON ZAA.COMPCODE = ZAB.GTCOMPMASTID   JOIN GTGENITEMMAST ZAC ON ZAC.GTGENITEMMASTID = ZAA.ITEMNAME WHERE ZAB.COMPCODE = AB.COMPCODE AND ZAC.ITEMNAME = AC.ITEMNAME  AND ZAA.COMPCODE=D.GTCOMPMASTID AND ZAA.FUELDATE <= A.TOKENDATE  )  )AS FUELRATE2  ,        CASE B.LITRES  WHEN  'FULL' THEN '0'    ELSE B.LITRES END as  LITRES,I.BUNKNAME,I.BUNKNAME AS ACTIVE,A.TOKENDATE,A.REMARKS,'" + MON + "' AS TODATE      FROM  ASPTBLVEHTOKEN A     JOIN ASPTBLVEHTOKENDET B ON A.ASPTBLVEHTOKENID=B.ASPTBLVEHTOKENID AND A.TOKENCANCEL='F'         JOIN GTCOMPMAST D ON D.GTCOMPMASTID=A.COMPCODE     JOIN HREMPLOYMAST E ON E.HREMPLOYMASTID=A.EMPNAME      JOIN hremploydetails F ON F.HREMPLOYMASTID=E.HREMPLOYMASTID         join HRVEHTYPEMAST G on G.HRVEHTYPEMASTid=A.VEHICLETYPE      JOIN GTGENITEMMAST H ON H.GTGENITEMMASTID=B.ITEMNAME   JOIN ASPTBLPETMAS I ON I.COMPCODE=D.GTCOMPMASTID AND I.COMPCODE=A.COMPCODE  AND  I.ASPTBLPETMASID=A.BUNKNAME  WHERE D.COMPCODE = '" + Class.Users.HCompcode + "'  AND A.TOKENDATE between TO_DATE('" + frmdate.Value.ToString("dd-MM-yyyy") + "','dd-MM-yyyy') and TO_DATE('" + todate.Value.ToString("dd-MM-yyyy") + "','dd-MM-yyyy') AND I.BUNKNAME='" + combobunk.Text + "')X    GROUP BY X.COMPCODE,X.VEHICLENO, X.VEHTYPE ,X.FNAME,X.ITEMNAME,X.DEPT ,X.BUNKNAME,X.ACTIVE,X.REMARKS,X.TODATE ORDER BY 1";
                                DataSet ds2 = Utility.ExecuteSelectQuery(sel2, "ASPTBLVEHTOKEN");
